export interface CSVOptions {
  delimiter?: string;
  quote?: string;
  lineSeparator?: string;
}

export interface CSVError {
  row: number;
  message: string;
}

export interface CSVResult<T extends Record<string, unknown> = Record<string, unknown>> {
  rows: T[];
  headers: string[];
  errors: CSVError[];
  filter(predicate: (row: T) => boolean): T[];
  sum(column: keyof T | string): number;
  average(column: keyof T | string): number;
  count(): number;
  groupBy(column: keyof T | string): Map<unknown, T[]>;
}

interface ParsedRow {
  fields: string[];
  line: number;
}

function coerceValue(value: string): unknown {
  if (value === "") {
    return null;
  }
  const trimmed = value.trim();
  if (trimmed === "") {
    return null;
  }
  const lower = trimmed.toLowerCase();
  if (lower === "null") {
    return null;
  }
  if (lower === "true") {
    return true;
  }
  if (lower === "false") {
    return false;
  }
  if (/^-?\d+(\.\d+)?$/.test(trimmed)) {
    const num = Number(trimmed);
    if (!Number.isNaN(num)) {
      return num;
    }
  }
  return value;
}

function parseRows(input: string, options?: CSVOptions): { rows: ParsedRow[]; errors: CSVError[] } {
  const delimiter = options?.delimiter ?? ",";
  const quote = options?.quote ?? '"';
  const lineSeparator = options?.lineSeparator ?? "\n";

  const rows: ParsedRow[] = [];
  const errors: CSVError[] = [];

  if (input.length === 0) {
    return { rows, errors };
  }

  let row: string[] = [];
  let field = "";
  let inQuotes = false;
  let i = 0;
  let lineNumber = 1;

  const delimiterLength = delimiter.length;

  const matchLineSeparator = (index: number): number => {
    if (lineSeparator === "\n" && input[index] === "\r" && input[index + 1] === "\n") {
      return 2;
    }
    if (input.startsWith(lineSeparator, index)) {
      return lineSeparator.length;
    }
    return 0;
  };

  while (i < input.length) {
    const char = input[i];

    if (inQuotes) {
      if (char === quote) {
        if (input[i + 1] === quote) {
          field += quote;
          i += 2;
          continue;
        }
        inQuotes = false;
        i += 1;
        continue;
      }
      field += char;
      i += 1;
      continue;
    }

    if (char === quote) {
      inQuotes = true;
      i += 1;
      continue;
    }

    const lineSepLength = matchLineSeparator(i);
    if (lineSepLength > 0) {
      row.push(field);
      rows.push({ fields: row, line: lineNumber });
      lineNumber += 1;
      row = [];
      field = "";
      i += lineSepLength;
      continue;
    }

    if (delimiterLength > 0 && input.startsWith(delimiter, i)) {
      row.push(field);
      field = "";
      i += delimiterLength;
      continue;
    }

    field += char;
    i += 1;
  }

  if (inQuotes) {
    errors.push({ row: lineNumber, message: "Unclosed quote" });
  }

  if (row.length > 0 || field !== "") {
    row.push(field);
    rows.push({ fields: row, line: lineNumber });
  }

  return { rows, errors };
}

export function parseCSV(input: string, options?: CSVOptions): CSVResult {
  const { rows: parsedRows, errors } = parseRows(input, options);

  if (parsedRows.length === 0) {
    return {
      rows: [],
      headers: [],
      errors,
      filter: () => [],
      sum: () => 0,
      average: () => 0,
      count: () => 0,
      groupBy: () => new Map(),
    };
  }

  const headers = parsedRows[0].fields;
  const rows: Record<string, unknown>[] = [];

  for (let index = 1; index < parsedRows.length; index += 1) {
    const { fields, line } = parsedRows[index];
    if (fields.length !== headers.length) {
      errors.push({
        row: line,
        message: `Row has ${fields.length} fields, expected ${headers.length}`,
      });
    }
    const row: Record<string, unknown> = {};
    for (let i = 0; i < headers.length; i += 1) {
      const header = headers[i];
      const value = i < fields.length ? fields[i] : "";
      row[header] = coerceValue(value);
    }
    rows.push(row);
  }

  const result: CSVResult = {
    rows,
    headers,
    errors,
    filter: (predicate) => rows.filter(predicate),
    sum: (column) => {
      let total = 0;
      for (const row of rows) {
        const value = row[column as string];
        if (typeof value === "number" && Number.isFinite(value)) {
          total += value;
        }
      }
      return total;
    },
    average: (column) => {
      let total = 0;
      let count = 0;
      for (const row of rows) {
        const value = row[column as string];
        if (typeof value === "number" && Number.isFinite(value)) {
          total += value;
          count += 1;
        }
      }
      return count === 0 ? 0 : total / count;
    },
    count: () => rows.length,
    groupBy: (column) => {
      const map = new Map<unknown, Record<string, unknown>[]>();
      for (const row of rows) {
        const key = row[column as string];
        const bucket = map.get(key);
        if (bucket) {
          bucket.push(row);
        } else {
          map.set(key, [row]);
        }
      }
      return map;
    },
  };

  return result;
}

import { parseCSV } from "./csv-parser";

function assert(condition: boolean, message: string): void {
  if (!condition) {
    throw new Error(message);
  }
}

function assertDeepEqual(actual: unknown, expected: unknown, message: string): void {
  const actualJson = JSON.stringify(actual);
  const expectedJson = JSON.stringify(expected);
  if (actualJson !== expectedJson) {
    throw new Error(`${message}\nExpected: ${expectedJson}\nActual:   ${actualJson}`);
  }
}

function runTests(): void {
  // basic parsing
  const basic = parseCSV("name,age\nAlice,30\nBob,25");
  assertDeepEqual(basic.headers, ["name", "age"], "Basic headers mismatch");
  assert(basic.rows.length === 2, "Basic rows length mismatch");
  assert(basic.rows[0].name === "Alice", "Basic row value mismatch");
  assert(basic.rows[0].age === 30, "Basic type coercion mismatch");

  // quoted fields with commas
  const quoted = parseCSV("name,comment\nAlice,\"Hello, world\"");
  assert(quoted.rows[0].comment === "Hello, world", "Quoted field parsing failed");

  // escaped quotes
  const escaped = parseCSV("name,quote\nBob,\"He said \"\"Hi\"\"\"");
  assert(escaped.rows[0].quote === "He said \"Hi\"", "Escaped quotes parsing failed");

  // custom delimiters and line separators
  const custom = parseCSV("a;b|1;2|3;4", { delimiter: ";", lineSeparator: "|" });
  assertDeepEqual(custom.headers, ["a", "b"], "Custom delimiter headers mismatch");
  assert(custom.rows.length === 2, "Custom delimiter rows length mismatch");
  assert(custom.rows[1].a === 3 && custom.rows[1].b === 4, "Custom delimiter data mismatch");

  // type coercion
  const types = parseCSV("a,b,c,d,e,f,g\n1,2.5,TRUE,false,null,,text");
  const row = types.rows[0];
  assert(row.a === 1, "Type coercion int failed");
  assert(row.b === 2.5, "Type coercion float failed");
  assert(row.c === true, "Type coercion true failed");
  assert(row.d === false, "Type coercion false failed");
  assert(row.e === null, "Type coercion null failed");
  assert(row.f === null, "Type coercion empty string failed");
  assert(row.g === "text", "Type coercion string failed");

  // malformed row error collection
  const malformed = parseCSV("a,b\n1,2,3\n4");
  assert(malformed.errors.length === 2, "Malformed row errors length mismatch");
  assert(malformed.errors[0].row === 2, "Malformed row error line mismatch");
  assert(malformed.errors[1].row === 3, "Malformed row error line mismatch");

  // filter functionality
  const filterResult = parseCSV("name,age\nAlice,30\nBob,20\nCara,40");
  const filtered = filterResult.filter((r) => (r.age as number) > 25);
  assert(filtered.length === 2, "Filter functionality failed");

  // aggregation methods
  const agg = parseCSV("name,city,score\nA,NY,10\nB,LA,20\nC,NY,30");
  assert(agg.sum("score") === 60, "Sum aggregation failed");
  assert(agg.average("score") === 20, "Average aggregation failed");
  assert(agg.count() === 3, "Count aggregation failed");
  const grouped = agg.groupBy("city");
  assert(grouped.size === 2, "GroupBy size mismatch");
  assert(grouped.get("NY")?.length === 2, "GroupBy content mismatch");

  // edge cases: empty input
  const empty = parseCSV("");
  assert(empty.headers.length === 0 && empty.rows.length === 0, "Empty input failed");

  // edge case: single column
  const singleColumn = parseCSV("a\n1\n2");
  assert(singleColumn.headers.length === 1 && singleColumn.rows.length === 2, "Single column failed");

  // edge case: single row
  const singleRow = parseCSV("a,b\n1,2");
  assert(singleRow.rows.length === 1, "Single row failed");

  // edge case: very large fields
  const largeField = "x".repeat(10000);
  const large = parseCSV(`data\n${largeField}`);
  assert((large.rows[0].data as string).length === 10000, "Large field parsing failed");
}

runTests();

